"""Test validation approach."""
import matplotlib.text as mtext

# Test validating kwargs against Text properties
t = mtext.Text()

# Valid kwargs
valid_kwargs = {"fontsize": 12, "color": "red"}
try:
    t._internal_update(valid_kwargs)
    print("Valid kwargs: OK")
except Exception as e:
    print("Valid kwargs ERROR: {}".format(e))

# Invalid kwargs
invalid_kwargs = {"xticklabels": ["a", "b"]}
try:
    t._internal_update(invalid_kwargs)
    print("Invalid kwargs: ERROR - should have raised exception")
except Exception as e:
    print("Invalid kwargs: OK - {}".format(e))

